dtsPropsFor.FitText:
/** Text to scale; glyphs fill the parent width via an SVG viewBox framed to the text's bounding box. */
children: string;
/** Text-presentation utilities applied to the painted <text> (weight, italic, color, tracking). */
className?: string;
/** font-* family utility applied before className. Defaults to "font-playfair". */
font?: string;

dtsPropsFor.NavbarItem:
/** Visible label. */
title: string;
/** Link target. */
href: string;

dtsPropsFor.SignInButton:
/** Icon node rendered beside the "SIGN IN WITH" label. */
icon: React.ReactNode;
/** OAuth provider; inert until set. */
provider?: "google" | "apple";

dtsPropsFor.Parallax:
/** Content that drifts on scroll. */
children: React.ReactNode;
/** Generic mode: px the block drifts as it passes through the viewport. */
distance?: number;
/** Hero mode: drift driven by page scroll, clamped to the next sibling's top. */
clampToNext?: boolean;
/** Classes applied to the moving element itself. */
className?: string;
